/**
 * Custom debounce hook. Returns a debounced copy of `value` that only
 * updates after `delay` ms have passed without `value` changing, plus an
 * `isPending` flag that is true while a change is waiting to settle.
 */
function useDebouncedValue(value, delay) {
    const [debounced, setDebounced] = useState(value);
    const [isPending, setIsPending] = useState(false);

    useEffect(() => {
        // Value already settled — nothing pending.
        if (value === debounced) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        const timeoutId = setTimeout(() => {
            setDebounced(value);
            setIsPending(false);
        }, delay);

        // Cleanup clears the pending timer on every change AND on unmount,
        // preventing state updates on an unmounted component (no memory leak).
        return () => clearTimeout(timeoutId);
    }, [value, delay, debounced]);

    return [debounced, isPending];
